const data = $input.first().json.body || $input.first().json;

// Email à envoyer 24h après la prestation
const datePrestation = new Date(data.prestation?.date || new Date());
const dateAvis = new Date(datePrestation.getTime() + 24 * 60 * 60 * 1000);

// Si la prestation est passée, envoyer dans 1h quand même
const maintenant = new Date();
const dateEnvoi = dateAvis < maintenant 
  ? new Date(maintenant.getTime() + 60 * 60 * 1000) 
  : dateAvis;

return [{
  json: {
    prestation: data.prestation,
    client: data.client,
    config: {
      nomEtablissement: data.config?.nomEtablissement || 'Notre établissement',
      urlAvisGoogle: data.config?.urlAvisGoogle || '',
      urlAvisInterne: data.config?.urlAvisInterne || '',
      emailExpedition: data.config?.emailExpedition || 'noreply@marrynov.re'
    },
    dateEnvoi: dateEnvoi.toISOString(),
    delaiSecondes: Math.max(0, Math.floor((dateEnvoi - maintenant) / 1000))
  }
}];
